package com.example.mfa;

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.web.bind.annotation.*;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.crypto.bcrypt.BCrypt;
import javax.persistence.*;
import java.util.List;
import java.util.UUID;
import org.springframework.data.jpa.repository.JpaRepository;
import java.util.stream.Collectors;
import java.util.stream.IntStream;

@SpringBootApplication
public class MfaApplication {
    public static void main(String[] args) {
        SpringApplication.run(MfaApplication.class, args);
    }
}

@RestController
@RequestMapping("/mfa")
class MfaController {

    @Autowired
    private BackupCodeRepository backupCodeRepository;

    @PostMapping("/enable")
    public List<String> enableMfa(@RequestParam String userId) {
        List<String> codes = IntStream.range(0, 5)
                .mapToObj(i -> UUID.randomUUID().toString())
                .collect(Collectors.toList());
        codes.forEach(code -> backupCodeRepository.save(new BackupCode(userId, BCrypt.hashpw(code, BCrypt.gensalt()))));
        return codes;
    }

    @PostMapping("/authenticate")
    public String authenticateWithBackupCode(@RequestParam String userId, @RequestParam String code) {
        List<BackupCode> codes = backupCodeRepository.findByUserId(userId);
        for (BackupCode backupCode : codes) {
            if (BCrypt.checkpw(code, backupCode.getCode())) {
                backupCodeRepository.delete(backupCode);
                return "Authentication successful";
            }
        }
        return "Authentication failed";
    }
}

@Entity
class BackupCode {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;
    private String userId;
    private String code;

    public BackupCode() {}

    public BackupCode(String userId, String code) {
        this.userId = userId;
        this.code = code;
    }

    public String getUserId() {
        return userId;
    }

    public String getCode() {
        return code;
    }
}

interface BackupCodeRepository extends JpaRepository<BackupCode, Long> {
    List<BackupCode> findByUserId(String userId);
}